class Solution {
public:
    int minDays(int n) {
        queue<pair<int, int>> q;
        unordered_set<int> visited;
        q.push({n, 0});
        visited.insert(n);

        while (!q.empty()) {
            auto [curr, days] = q.front();
            q.pop();

            if (curr == 0) return days;

            if (curr % 3 == 0 && visited.find(curr - 2 * (curr / 3)) == visited.end()) {
                q.push({curr - 2 * (curr / 3), days + 1});
                visited.insert(curr - 2 * (curr / 3));
            }
            if (curr % 2 == 0 && visited.find(curr - curr / 2) == visited.end()) {
                q.push({curr - curr / 2, days + 1});
                visited.insert(curr - curr / 2);
            }
            if (visited.find(curr - 1) == visited.end()) {
                q.push({curr - 1, days + 1});
                visited.insert(curr - 1);
            }
        }
        return -1; // This line will never be reached given the constraints.
    }
};
